// Generate personalized motivation messages
const userData = $input.all();
const messages = [];

for (const user of userData) {
  const data = user.json;
  let message = '';
  let emoji = '💪';
  let suggestion = '';

  const hoursSince = Math.floor(data.hours_since_last_meal || 48);

  if (data.last_meal_date === null) {
    message = `Welcome back ${data.name}! It's time to start your nutrition journey!`;
    suggestion = 'Try logging a simple breakfast to get started.';
    emoji = '🌟';
  } else if (hoursSince >= 48) {
    message = `Hey ${data.name}! We miss you at CalAI!`;
    suggestion = 'It\'s been 2 days since your last meal log. Let\'s get back on track!';
    emoji = '📱';
  } else if (hoursSince >= 36) {
    message = `Hi ${data.name}! Don't break your streak!`;
    suggestion = 'You\'re so close to maintaining your daily logging habit!';
    emoji = '🔥';
  }

  messages.push({
    user_id: data.id,
    email: data.email,
    name: data.name,
    hours_since_last_meal: hoursSince,
    message: message,
    suggestion: suggestion,
    emoji: emoji,
    quick_meals: [
      'Greek Yogurt with Berries (300 cal, 20g protein)',
      'Avocado Toast (250 cal, healthy fats)',
      'Protein Smoothie (350 cal, 25g protein)',
      'Chicken Salad (400 cal, 35g protein)'
    ]
  });
}

return messages.map(msg => ({ json: msg }));

// Log the re-engagement attempt for analytics
const userData = $input.all();
const logs = [];

for (const user of userData) {
  const data = user.json;

  logs.push({
    user_id: data.user_id,
    email: data.email,
    hours_since_last_meal: data.hours_since_last_meal,
    campaign_type: 'streak_maintenance',
    sent_at: new Date().toISOString(),
    success: true
  });
}

return logs.map(log => ({ json: log }));
